   171	int8_t nr_get_DELTA_PREAMBLE(module_id_t mod_id, int CC_id, uint16_t prach_format)
   172	{
   173	  NR_UE_MAC_INST_t *mac = get_mac_inst(mod_id);
   174	  NR_RACH_ConfigCommon_t *nr_rach_ConfigCommon = mac->current_UL_BWP.rach_ConfigCommon;
   175	  NR_SubcarrierSpacing_t scs = *nr_rach_ConfigCommon->msg1_SubcarrierSpacing;
   176	  int prach_sequence_length = nr_rach_ConfigCommon->prach_RootSequenceIndex.present - 1;
   177	  uint8_t prachConfigIndex, mu;
   178	
   179	  AssertFatal(CC_id == 0, "Transmission on secondary CCs is not supported yet\n");
   180	
   181	  // SCS configuration from msg1_SubcarrierSpacing and table 4.2-1 in TS 38.211
   182	
   183	  switch (scs){
   184	    case NR_SubcarrierSpacing_kHz15:
   185	    mu = 0;
   186	    break;
   187	
   188	    case NR_SubcarrierSpacing_kHz30:
   189	    mu = 1;
   190	    break;
   191	
   192	    case NR_SubcarrierSpacing_kHz60:
   193	    mu = 2;
   194	    break;
